        import sailpoint.object.Identity; 
        import sailpoint.object.Custom; 
        import sailpoint.tools.Util; 
        
        String locationName= "";
        String depName= "";
        String businessID ="";
        String buildId= "";
        String depatId= "";
        String buCode= "";
        String buDesc= "";
        
        Identity identity = context.getObjectByName(Identity.class, identityName);

        if (identity != null) {       
          if ( null != identityModel){
        		if(Util.isNotNullOrEmpty(identityModel.get("domain")) ) {       
              identity.setAttribute("domain", identityModel.get("domain"));
            }       
            else{
              Custom defaultValue = context.getObjectByName(Custom.class,"Ascension-Custom-ContractorConfiguration");
              String defaultValues= "";
              String ministries = identity.getAttribute("ministry");

              if (defaultValue != null && null != defaultValue.get("DefaultDomain") && Util.isNotNullOrEmpty(defaultValue.get("DefaultDomain").get(ministries))) {                        	         
                defaultValues = defaultValue.get("DefaultDomain").get(ministries);
                identity.setAttribute("domain", defaultValues);
                //comment decache //context.decache(defaultValue);
              } 
        		}
        	}
        	
        if((null != identityModel && Util.nullSafeCaseInsensitiveEq(identityModel.get("domain"),"amita")) || Util.nullSafeCaseInsensitiveEq(identity.getAttribute("domain"),"amita")){
            if(Util.isNotNullOrEmpty(identity.getAttribute("location"))){
              locationName = identity.getAttribute("location");       
              buildId = getLocationID(locationName);
        			identity.setAttribute("buildingId",buildId);
            }
            if(Util.isNotNullOrEmpty(identity.getAttribute("department"))){
              depName = identity.getAttribute("department");       
              depatId = getDepartmentID(depName);
       				identity.setAttribute("departmentNumber",depatId);
            }
        		if(Util.isNotNullOrEmpty(depatId) && Util.isNotNullOrEmpty(buildId)){              
              buCode = getBusinessCode(depatId,buildId);        
        			identity.setAttribute("businessUnit",buCode);
            }
        		if(Util.isNotNullOrEmpty(buCode)){                     
              buDesc = getBusinessDesc(buCode);
        			identity.setAttribute("businessUnitDescription",buDesc);
            }
        	}
      	  context.startTransaction();
        	context.saveObject(identity);
        	context.commitTransaction();	
        	//comment decache //context.decache(identity);
        }

        import sailpoint.api.SailPointContext;
        import sailpoint.object.Identity;
        import sailpoint.object.Application;
        import sailpoint.tools.Util;
        import sailpoint.object.ProvisioningPlan;
        import sailpoint.object.ProvisioningPlan.AccountRequest;
        import sailpoint.object.ProvisioningPlan.AttributeRequest;
        import sailpoint.object.Custom; 

        ProvisioningPlan plan = new ProvisioningPlan();

        Identity identityObject = context.getObjectByName(Identity.class, identityName);
        Custom custRole = context.getObjectByName(Custom.class,"Ascension-Custom-AD-DomainMapping");
        
        List roleNames = new ArrayList();
        String domainAD = null;
        String ministryAD = null;
        HashMap domainMap = new HashMap();

        if( null != identityObject){
          domainAD = identityObject.getAttribute("domain");
          ministryAD = identityObject.getAttribute("ministry");       	
        }
		
		if(Util.isNotNullOrEmpty(domainAD)){     
        	domainAD = domainConversion(domainAD);
   		}

        if (custRole != null && null != custRole.get("DomainOUMapping")) {
          domainMap = custRole.get("DomainOUMapping");
          if(null != domainMap && !domainMap.isEmpty() && null != domainMap.get(domainAD)){ 
          	roleNames = domainMap.get(domainAD).get("RoleName");
          }
          //comment decache //context.decache(custRole);
        }  

        if(null != roleNames && !roleNames.isEmpty()){
          ProvisioningPlan.AccountRequest acctRoleReq = new ProvisioningPlan.AccountRequest();
          acctRoleReq.setApplication("IIQ");
          acctRoleReq.setNativeIdentity(identityName);
          acctRoleReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Modify);    
          for (String roleName: roleNames) {
            AttributeRequest attributeRequest = new AttributeRequest(ProvisioningPlan.ATT_IIQ_ASSIGNED_ROLES , ProvisioningPlan.Operation.Add, roleName);
            acctRoleReq.add(attributeRequest);
          } 

          plan.add(acctRoleReq);          

          if(null != identityObject){
            plan.setIdentity(identityObject);
            //comment decache //context.decache(identityObject);
          }
        }
        return plan;

		
          import sailpoint.object.Identity;
          
         	Identity identity = context.getObjectByName(Identity.class,identityName);  
          boolean status = false;
          String domainValue = "";

          if(null != identity){
            domainValue = identity.getAttribute("domain");            
          
            if (Util.nullSafeCaseInsensitiveEq(domainValue,"AMITA")) {
              status = true;
            }
           //comment decache //context.decache(identity);
          }
		  		return status;

		
         import sailpoint.object.Custom;
          
         Custom custom = context.getObjectByName(Custom.class, "Ascension-custom-generalConfiguration");       				
         if(custom != null && custom.get("ServiceNowNotificationSchedule") !=null){
          
            advanceTime = custom.get("ServiceNowNotificationSchedule");
            //comment decache //context.decache(custom);
          
           	return advanceTimeByMinutes(advanceTime);         
         }
